// src/utils/pagination.ts
export interface PageBounds {
  start: number;
  end: number;
}

// Callers pass 1-indexed page numbers (page 1 is the first page).
// BUG: start = page * pageSize makes page 1 -> start 10 (with pageSize 10),
// silently dropping the first page of results in production.
export function getPageBounds(page: number, pageSize: number): PageBounds {
  const start = page * pageSize;
  const end = start + pageSize;
  return { start, end };
}

export function paginate<T>(items: T[], page: number, pageSize: number): T[] {
  const { start, end } = getPageBounds(page, pageSize);
  return items.slice(start, end);
}

// src/lib/discount.ts
/**
 * computeDiscount — loyalty discount on a cart total.
 *
 * Tiering rules (spec):
 *   - bronze: 0% always
 *   - silver: 5%, applies only when cartTotal is over $50
 *   - gold:   10%, applies only when cartTotal is over $100
 * Below a tier's threshold the discount is 0.
 *
 * @param cartTotal pre-discount cart total in dollars
 * @param tier "bronze" | "silver" | "gold"
 * @returns discount amount in dollars
 */
export function computeDiscount(cartTotal: number, tier: string): number {
  if (tier === "gold" && cartTotal > 100) return cartTotal * 0.1;
  if (tier === "silver" && cartTotal > 50) return cartTotal * 0.05;
  return 0;
}
